# EVOLVE-BLOCK-START
import numpy as np
from scipy.optimize import minimize

def construct_packing():
    n = 26
    best_sum, best_c, best_r = 0, None, None
    ii, jj = np.triu_indices(n, 1)

    def fv(x):
        return -np.sum(np.exp(x[2*n:]))
    def cwv(x):
        c, r = x[:2*n].reshape(n,2), np.exp(x[2*n:])
        return np.r_[c[:,0]-r, 1-c[:,0]-r, c[:,1]-r, 1-c[:,1]-r]
    def ccv(x):
        c, r = x[:2*n].reshape(n,2), np.exp(x[2*n:])
        return np.sqrt(((c[ii]-c[jj])**2).sum(1)) - r[ii] - r[jj]
    cons = [{'type':'ineq','fun':cwv},{'type':'ineq','fun':ccv}]

    def valid(c, r, tol=1e-6):
        if np.any(c[:,0]-r<-tol) or np.any(c[:,0]+r>1+tol): return False
        if np.any(c[:,1]-r<-tol) or np.any(c[:,1]+r>1+tol): return False
        d = np.sqrt(((c[ii]-c[jj])**2).sum(1))
        return np.all(d >= r[ii]+r[jj]-tol)

    def make_hex(r, rows, offs):
        dx, dy = 2*r, r*3**0.5
        pts = []
        for i, cnt in enumerate(rows):
            y = r + i*dy
            for j in range(cnt):
                pts.append([r + offs[i]*r + j*dx, y])
        c = np.array(pts[:n])
        xm, ym = c[:,0].max()+r, c[:,1].max()+r
        sc = min(1/xm, 1/ym)
        return c*sc, np.full(n, r*sc)

    configs = []
    row_configs = [
        ([6,5,6,5,4],[0,1,0,1,0]),([5,6,5,6,4],[1,0,1,0,0]),
        ([6,5,6,5,4],[0,1,0,1,1]),([5,5,6,5,5],[0,1,0,1,0]),
        ([5,6,5,5,5],[1,0,1,0,1]),([6,5,5,5,5],[0,1,0,1,0]),
        ([5,5,5,6,5],[0,1,0,1,0]),([6,5,6,4,5],[0,1,0,1,0]),
        ([5,6,6,5,4],[1,0,0,1,0]),([4,5,6,5,6],[0,1,0,1,0]),
    ]
    for r0 in [0.0995, 0.1005, 0.1010, 0.10127, 0.1015, 0.1020, 0.1025]:
        for rows, offs in row_configs:
            if sum(rows) >= n:
                configs.append(make_hex(r0, rows, offs))

    def optimize_config(c0, r0):
        nonlocal best_sum, best_c, best_r
        def fu(x): return -n*np.exp(x[-1])
        def cwu(x):
            c, r = x[:2*n].reshape(n,2), np.exp(x[-1])
            return np.r_[c[:,0]-r, 1-c[:,0]-r, c[:,1]-r, 1-c[:,1]-r]
        def ccu(x):
            c, r = x[:2*n].reshape(n,2), np.exp(x[-1])
            return np.sqrt(((c[ii]-c[jj])**2).sum(1)) - 2*r
        x0 = np.r_[c0.ravel(), np.log(r0[0])]
        res = minimize(fu, x0, method='SLSQP',
            constraints=[{'type':'ineq','fun':cwu},{'type':'ineq','fun':ccu}],
            options={'maxiter':5000,'ftol':1e-14})
        cu = res.x[:2*n].reshape(n,2); ru = np.full(n, np.exp(res.x[-1]))
        if not valid(cu, ru): return
        x1 = np.r_[cu.ravel(), np.log(ru)]
        for ftol in [1e-10, 1e-13]:
            res2 = minimize(fv, x1, method='SLSQP', constraints=cons, options={'maxiter':10000,'ftol':ftol})
            cv, rv = res2.x[:2*n].reshape(n,2), np.exp(res2.x[2*n:])
            if valid(cv,rv) and np.sum(rv)>best_sum:
                best_sum, best_c, best_r = np.sum(rv), cv.copy(), rv.copy()
                x1 = res2.x
        for s in range(12):
            np.random.seed(s+7)
            xp = np.r_[best_c.ravel(), np.log(best_r)]
            xp[:2*n] += np.random.randn(2*n)*0.005
            xp[2*n:] += np.random.randn(n)*0.005
            res3 = minimize(fv, xp, method='SLSQP', constraints=cons, options={'maxiter':10000,'ftol':1e-14})
            c3, r3 = res3.x[:2*n].reshape(n,2), np.exp(res3.x[2*n:])
            if valid(c3,r3) and np.sum(r3)>best_sum:
                best_sum, best_c, best_r = np.sum(r3), c3.copy(), r3.copy()

    for c0, r0 in configs:
        try: optimize_config(c0, r0)
        except: pass

    return best_c, best_r, float(best_sum)
# EVOLVE-BLOCK-END

def run_packing():
    centers, radii, sum_radii = construct_packing()
    return centers, radii, sum_radii

if __name__ == "__main__":
    centers, radii, sum_radii = run_packing()
    print(f"Sum of radii: {sum_radii}")
